import json
import re

# Read the Swift repositories from var_functions.query_db:13
# Since it's stored in a file, we need to read it
import os
result_file = var_functions.query_db:13
if isinstance(result_file, str) and result_file.endswith('.json'):
    with open(result_file, 'r') as f:
        swift_repos = json.load(f)
else:
    swift_repos = var_functions.query_db:13

# Read Swift file contents from var_functions.query_db:14
if isinstance(var_functions.query_db:14, str) and var_functions.query_db:14.endswith('.json'):
    with open(var_functions.query_db:14, 'r') as f:
        swift_files = json.load(f)
else:
    swift_files = var_functions.query_db:14

# Filter swift files to find non-binary ones with duplication info
filtered_files = []
for file in swift_files:
    desc = file.get('repo_data_description', '')
    if 'non-binary' in desc and 'duplicat' in desc:
        # Extract duplication count from description
        match = re.search(r'duplicated (\d+) time', desc)
        if match:
            duplications = int(match.group(1))
            filtered_files.append({
                'id': file['id'],
                'repo_name': file['sample_repo_name'],
                'path': file['sample_path'],
                'duplications': duplications
            })

# Find the file with most duplications
if filtered_files:
    max_file = max(filtered_files, key=lambda x: x['duplications'])
    result = {
        'repository': max_file['repo_name'],
        'file_id': max_file['id'],
        'file_path': max_file['path'],
        'duplications': max_file['duplications']
    }
else:
    result = {'error': 'No non-binary Swift files found with duplication data'}

print('__RESULT__:')
print(json.dumps(result))

